previewCss:
.darma-loader-darma-custom-641 {color: var(--loader-color, #f97316);
  --loader-secondary-color: var(--loader-secondary-color, #facc15);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 90px;
   height: 30px;
   box-shadow: 0 3px 0 currentColor;
   --g:repeat-x repeating-linear-gradient(90deg,var(--loader-secondary-color, #facc15) 0 16px,#0000 0 18px,var(--loader-secondary-color, #facc15) 0 34px,#0000 0 100%);
   background: var(--g),var(--g);
   background-size: 60px 14px,60px 14px;
   animation: darma-loader-darma-custom-641-l8 1s infinite linear;
}
@keyframes darma-loader-darma-custom-641-l8  {
  0% {background-position:0 0,0 100%}
100% {background-position:60px 0,60px 100%}
}

